+    // Check for unified path and freeze file
+    if let Some(ref unified_path) = details.unified_path {
+        let freeze_path = format!("/sys/fs/cgroup{}/cgroup.freeze", unified_path);
+        Path::new(&freeze_path).exists()
+    } else {
+        false
+    }
+}
